package loops;

public class looop {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		int n = 5;
		int a = 0;

		for (int i = n; i >= 1; i--) {

			for (int j =1; j <= i-1; j++) {
				
				for (int k=i; k>=i-1; k--) {
					
					System.out.print("");
				}
				
				System.out.print("");
			}
			
			
			
			System.out.println("");
		}
		
	}

}
